#!/usr/bin/env node
// Packs the hello-agent reference fixture reproducibly and pins its exact
// npm-shaped identity (name, version, SHA-512 tarball integrity) plus the
// staged file contents into a generated module. The binding installs only
// these generated bytes; any fixture edit without regeneration fails
// `npm run hello-agent:check`.
import { createHash } from "node:crypto";
import { mkdir, mkdtemp, readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { basename, join, resolve } from "node:path";
import { spawnSync } from "node:child_process";

const root = process.cwd();
const checkOnly = process.argv.includes("--check");
const npmCli = process.env.npm_execpath;
const fixtureRoot = resolve(root, "packages", "hello-agent-binding", "fixture");
const outputPath = resolve(root, "packages", "hello-agent-binding", "hello-agent-artifact.generated.mjs");
const FIXTURE_FILES = ["hello-agent.mjs", "package.json", "protocol.json"];

function run(command, args, options = {}) {
  const result = spawnSync(command, args, {
    encoding: "utf8",
    stdio: ["ignore", "pipe", "pipe"],
    ...options
  });
  if (result.status !== 0) {
    throw new Error(`${basename(command)} ${args[0] ?? ""} failed: ${(result.stderr || result.stdout || result.error?.message || "").trim()}`);
  }
  return result.stdout.trim();
}

// Windows cannot spawn npm's .cmd shim directly, so prefer the invoking npm's JS entry point.
function runNpm(args, options = {}) {
  if (npmCli && /\.[cm]?js$/u.test(npmCli)) return run(process.execPath, [npmCli, ...args], options);
  return run("npm", args, { ...options, shell: process.platform === "win32" });
}

function sha256Hex(value) {
  return createHash("sha256").update(value).digest("hex");
}

async function pack(destination) {
  await mkdir(destination, { recursive: true });
  const output = runNpm(["pack", "--json", "--pack-destination", destination], {
    cwd: fixtureRoot,
    env: { ...process.env, npm_config_ignore_scripts: "true" }
  });
  let packed;
  try {
    const manifest = JSON.parse(output);
    const entries = Array.isArray(manifest) ? manifest : Object.values(manifest);
    if (entries.length !== 1) throw new Error("unexpected npm pack manifest count");
    [packed] = entries;
  } catch {
    throw new Error("npm pack did not return its JSON manifest");
  }
  if (!packed?.filename || !Array.isArray(packed.files)) throw new Error("npm pack manifest is incomplete");
  const packedPaths = packed.files.map((file) => file.path).sort();
  if (JSON.stringify(packedPaths) !== JSON.stringify(FIXTURE_FILES)) {
    throw new Error(`hello-agent tarball contents drifted: ${packedPaths.join(", ")}`);
  }
  return { manifest: packed, path: resolve(destination, packed.filename) };
}

async function buildGeneratedModule() {
  const manifest = JSON.parse(await readFile(resolve(fixtureRoot, "package.json"), "utf8"));
  if (manifest.name !== "clawsembly-hello-agent" || manifest.private !== true
    || !/^[0-9]+\.[0-9]+\.[0-9]+$/u.test(manifest.version ?? "")) {
    throw new Error("hello-agent fixture manifest identity is invalid");
  }

  const temporaryRoot = await mkdtemp(join(tmpdir(), "clawsembly-hello-agent-"));
  try {
    const first = await pack(resolve(temporaryRoot, "pack-a"));
    const second = await pack(resolve(temporaryRoot, "pack-b"));
    const firstBytes = await readFile(first.path);
    const secondBytes = await readFile(second.path);
    if (sha256Hex(firstBytes) !== sha256Hex(secondBytes)) {
      throw new Error("hello-agent tarball is not byte-reproducible");
    }
    const integrity = `sha512-${createHash("sha512").update(firstBytes).digest("base64")}`;

    const files = [];
    for (const relativePath of FIXTURE_FILES) {
      const contents = await readFile(resolve(fixtureRoot, relativePath), "utf8");
      if (contents.includes("\r")) {
        throw new Error(`hello-agent fixture file ${relativePath} must use LF line endings`);
      }
      files.push({
        relativePath,
        bytes: Buffer.byteLength(contents, "utf8"),
        sha256: sha256Hex(contents),
        contents
      });
    }
    const protocolText = files.find((file) => file.relativePath === "protocol.json").contents;
    const protocol = JSON.parse(protocolText);
    if (protocol.schemaVersion !== 1 || protocol.protocol !== "clawsembly-hello/1"
      || !Array.isArray(protocol.methods) || protocol.methods.length !== 1
      || protocol.methods[0]?.name !== "hello.say") {
      throw new Error("hello-agent protocol descriptor must declare exactly hello.say");
    }

    const descriptor = {
      schemaVersion: 1,
      name: manifest.name,
      version: manifest.version,
      integrity,
      tarballBytes: firstBytes.byteLength,
      registryPublished: false,
      protocol: protocol.protocol,
      protocolFile: "protocol.json",
      protocolSha256: sha256Hex(protocolText),
      entrypoint: "hello-agent.mjs",
      files
    };
    return [
      "// Generated by scripts/generate-hello-agent-artifact.mjs. Do not edit.",
      "// Exact npm-shaped identity and verified sources for the hello-agent",
      "// reference binding fixture. registryPublished stays false until the",
      "// fixture is deliberately published; nothing may claim otherwise.",
      "// Regenerate with: npm run hello-agent:generate",
      `const artifact = ${JSON.stringify(descriptor, null, 2)};`,
      "for (const file of artifact.files) Object.freeze(file);",
      "Object.freeze(artifact.files);",
      "export const HELLO_AGENT_ARTIFACT = Object.freeze(artifact);",
      ""
    ].join("\n");
  } finally {
    await rm(temporaryRoot, { recursive: true, force: true });
  }
}

const generated = await buildGeneratedModule();
if (checkOnly) {
  const existing = await readFile(outputPath, "utf8").catch(() => "");
  if (existing !== generated) {
    console.error("hello-agent artifact drifted from its fixture; run: npm run hello-agent:generate");
    process.exit(1);
  }
  process.stdout.write("Verified the generated hello-agent artifact matches its fixture.\n");
} else {
  await writeFile(outputPath, generated);
  process.stdout.write(`Wrote ${outputPath}\n`);
}
